use std::time::Duration;

struct SiteStatus {
    name: String,
    is_up: bool,
    latency_ms: u64,
}

async fn check_site(name: impl AsRef<str>) -> Result<SiteStatus, std::io::Error> {
    let name_ref = name.as_ref().to_string();
    println!("Checking site: {}", name_ref);

    if name_ref.contains("fail") {
        return Err(std::io::Error::new(std::io::ErrorKind::TimedOut, "Connection timeout"));
    }

    let latency = if name_ref.contains("slow") {
        500
    } else {
        100
    };

    tokio::time::sleep(Duration::from_millis(latency as u64)).await;

    Ok(SiteStatus {
        name: name_ref,
        is_up: true,
        latency_ms: latency,
    })
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    let sites = vec!["google.com", "github.com/fail", "api.slow.net"];

    let mut handles = Vec::new();

    for site in sites {
        let handle = tokio::spawn(check_site(site));
        handles.push(handle);
    }

    let results: Vec<Result<SiteStatus, std::io::Error>> = futures::future::join_all(handles)
        .await
        .into_iter() // The join_all returns a collection of JoinHandles, which we then process here.
        .map(|join_result| match join_result {
            Ok(inner_result) => inner_result,
            Err(e) => Err(std::io::Error::new(std::io::ErrorKind::Other, format!("Task panicked: {}", e))) 
        })
        .collect();

    println!("
--- Analysis Complete ---");
    for result in results {
        match result {
            Ok(status) => println!("✅ {}: Up ({}ms)", status.name, status.latency_ms),
            Err(e) => println!("❌ Error checking site: {}", e.to_string()),
        }
    }

    Ok(())
}

use std::error::Error;

struct SensorReading {
    timestamp_ms: u64,
    value: f64,
}

trait DataProcessor {
    async fn process(&self, raw_data: Vec<u8>) -> Result<Vec<SensorReading>, String>;
}

struct UsbHidProcessor;

impl DataProcessor for UsbHidProcessor {
    async fn process(&self, raw_data: Vec<u8>) -> Result<Vec<SensorReading>, String> {
        if raw_data.len() < 10 {
            return Err("Insufficient data payload".to_string());
        }
        let mut readings = Vec::new();
        for i in (0..raw_data.len()).step_by(4) {
            if i + 8 >= raw_data.len() {
                break;
            }
            let timestamp_bytes: [u8; 8] = raw_data[i..i+8].try_into().unwrap();
            let value_bytes: [u8; 4] = raw_data[i+8..i+12].try_into().unwrap();

            let timestamp_ms = u64::from_le_bytes(timestamp_bytes);
            let value = f32::from_le_bytes(value_bytes) as f64;
            readings.push(SensorReading { timestamp_ms, value });
        }
        Ok(readings)
    }
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn Error>> {
    let raw_data = vec![0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0xaa, 0xbb, 0xcc, 0xdd];
    let processor = UsbHidProcessor;
    match processor.process(raw_data).await {
        Ok(readings) => {
            println!("Successfully processed {} readings.", readings.len());
            for reading in &readings[..std::cmp::min(2, readings.len())] {
                print!("Timestamp: {}, Value: {:.4} | ", reading.timestamp_ms, reading.value);
            }
            println!("...");
        }
        Err(e) => {
            eprintln!("Processing failed: {}", e);
        }
    }
    Ok(())
}
